import * as React from 'react';
import { Card } from '@tale-ui/react/card';
import { Row } from '@tale-ui/react/row';
import { Text } from '@tale-ui/react/text';

export function SelectableThemeCards() {
  const [selectedTheme, setSelectedTheme] = React.useState('harbour');

  return (
    <Row role="group" aria-label="Theme actions" gap="s">
      <Card.Button
        padding="sm"
        isSelected={selectedTheme === 'harbour'}
        onPress={() => setSelectedTheme('harbour')}
      >
        <Text as="span" variant="label" size="m">Harbour</Text>
        <Text as="span" variant="text" size="s" color="muted">
          Deep teal with a warm stone neutral.
        </Text>
      </Card.Button>
      <Card.Button
        padding="sm"
        isSelected={selectedTheme === 'fern'}
        onPress={() => setSelectedTheme('fern')}
      >
        <Text as="span" variant="label" size="m">Fern</Text>
        <Text as="span" variant="text" size="s" color="muted">
          Leaf green with a botanical neutral.
        </Text>
      </Card.Button>
    </Row>
  );
}
